import React, { useRef } from "react";
import "bootstrap/dist/css/bootstrap.min.css";

export default function TicketVenta({ ticket, setTicket }) {
  const ticketRef = useRef(null);

  const imprimirTicket = () => {
    if (!ticketRef.current) return;

    const ventana = window.open("", "", "width=350,height=600");
    ventana.document.write(`
      <html>
        <head>
          <title>Ticket de Venta</title>
          <style>
            body {
              font-family: Arial, sans-serif;
              font-size: 13px;
              padding: 10px;
            }
            h4 {
              text-align: center;
              margin-bottom: 5px;
            }
            hr {
              border: 1px dashed #000;
            }
            table {
              width: 100%;
              border-collapse: collapse;
            }
            th, td {
              padding: 3px;
              text-align: left;
            }
            th {
              border-bottom: 1px solid #000;
            }
            .totales p {
              display: flex;
              justify-content: space-between;
              margin: 3px 0;
            }
          </style>
        </head>
        <body>
          ${ticketRef.current.innerHTML}
        </body>
      </html>
    `);
    ventana.document.close();
    ventana.print();
  };

  if (!ticket) return null;

  return (
    <div
      ref={ticketRef}
      className="card mt-4 p-3 shadow"
      style={{ width: "350px", margin: "0 auto", fontSize: "13px" }}
    >
      <h4>🧾 TICKET DE VENTA</h4>
      <p className="text-center mb-1">{ticket.EmisorNombre}</p>
      <hr />

      <p><strong>Cliente:</strong> {ticket.NombreCliente}</p>
      <p><strong>Fecha:</strong> {new Date(ticket.Fecha).toLocaleString()}</p>
      <p><strong>No. Venta:</strong> {ticket.NumeroSecuencia}</p>

      <hr />

      <table>
        <thead>
          <tr>
            <th>Producto</th>
            <th>Cant</th>
            <th>Subt</th>
          </tr>
        </thead>
        <tbody>
          {ticket.productos.map((p, idx) => (
            <tr key={idx}>
              <td>{p.Nombre}</td>
              <td>{p.Cantidad}</td>
              <td>${p.Subtotal.toFixed(2)}</td>
            </tr>
          ))}
        </tbody>
      </table>

      <hr />

      <div className="totales">
        <p>
          <span>Subtotal:</span>
          <span>${ticket.Subtotal.toFixed(2)}</span>
        </p>
        <p>
          <span>IVA:</span>
          <span>${ticket.IVA.toFixed(2)}</span>
        </p>
        <p className="fw-bold">
          <span>Total:</span>
          <span>${ticket.Total.toFixed(2)}</span>
        </p>
      </div>

      <div className="d-flex justify-content-between mt-3">
        <button className="btn btn-primary btn-sm" onClick={imprimirTicket}>
          🖨 Imprimir
        </button>
        <button className="btn btn-secondary btn-sm" onClick={() => setTicket(null)}>
          ❌ Cerrar
        </button>
      </div>
    </div>
  );
}
